'use client';

import { motion, AnimatePresence } from 'framer-motion';
import { useEffect, useState } from 'react';

const testimonials = [
  {
    quote: 'Aromea feels like cinema. Every spray is a new scene in a beautifully crafted sensory experience.',
    author: 'Victoria M., fragrance curator',
  },
  {
    quote: 'The composition and longevity are so refined it feels like the perfume is designed for the soul.',
    author: 'James H., luxury consultant',
  },
  {
    quote: "I've never experienced a landing page and a fragrance so seamlessly aligned with modern luxury.",
    author: 'Lucia P., brand strategist',
  }
];

export default function TestimonialsSlider() {
  const [active, setActive] = useState(0);

  useEffect(() => {
    const timer = window.setInterval(() => {
      setActive((current) => (current + 1) % testimonials.length);
    }, 5000);
    return () => window.clearInterval(timer);
  }, []);

  return (
    <div className="relative overflow-hidden rounded-[2.25rem] border border-white/10 bg-[#110a07]/95 p-10 shadow-glow sm:p-14">
      <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,_rgba(255,184,92,0.14),_transparent_28%)]" />
      <div className="relative grid gap-8">
        <AnimatePresence mode="wait">
          <motion.div
            key={active}
            initial={{ opacity: 0, y: 30 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -30 }}
            transition={{ duration: 0.75, ease: 'easeOut' }}
            className="space-y-6"
          >
            <p className="text-3xl leading-tight text-white md:text-4xl">“{testimonials[active].quote}”</p>
            <p className="text-sm uppercase tracking-[0.35em] text-amber-200/80">{testimonials[active].author}</p>
          </motion.div>
        </AnimatePresence>
        <div className="flex items-center gap-3">
          {testimonials.map((item, index) => (
            <button
              key={item.author}
              onClick={() => setActive(index)}
              className={`h-2.5 w-2.5 rounded-full transition ${index === active ? 'bg-amber-200' : 'bg-white/20 hover:bg-white/35'}`}
            />
          ))}
        </div>
      </div>
    </div>
  );
}
